// Portable CLI verbs (info / validate / tree / audit / version) — issue #367.
//
// These execute the *self-hosted* cli_core verbs: `cli_rt.h` is generated by
// library-compiling dart/self_host/cli.ball.json through ball_cpp_compile (see
// dart/compiler/tool/gen_cli_cpp.dart). So the report text is byte-identical to
// the Dart CLI (proven by cpp/test/test_cli_parity.cpp) — a single source of
// truth, not a hand-reimplementation.
//
// cli_rt.h is the ONLY place its global BallDyn runtime is included, so its
// non-inline cli_core::* functions have exactly one definition in the `ball`
// binary (see the two-TU link test in the issue #367 PR).

#include <fstream>
#include <iostream>
#include <sstream>
#include <string>

#include <nlohmann/json.hpp>

#include "cli_commands.h"
#include "cli_rt.h"

#ifndef BALL_CLI_VERSION
#define BALL_CLI_VERSION "0.0.0"
#endif

namespace {

// proto3-JSON → BallDyn map tree (the shape the compiled cli_core reads). The
// verbs only inspect names/counts/presence (no expression-literal values), so a
// straight object→BallMap / array→BallList / scalar mapping suffices — the
// `@type` envelope key is stripped. Proven byte-exact over the conformance
// corpus by test_cli_parity.
std::any json_to_ball(const nlohmann::json& j) {
    if (j.is_null()) return std::any{};
    if (j.is_boolean()) return std::any(j.get<bool>());
    if (j.is_string()) return std::any(j.get<std::string>());
    if (j.is_number_integer())
        return std::any(static_cast<int64_t>(j.get<int64_t>()));
    if (j.is_number()) return std::any(j.get<double>());
    if (j.is_array()) {
        BallList l;
        for (const auto& e : j) l.push_back(json_to_ball(e));
        return std::any(l);
    }
    if (j.is_object()) {
        BallMap m;
        for (auto it = j.begin(); it != j.end(); ++it) {
            if (it.key() == "@type") continue;
            m[it.key()] = json_to_ball(it.value());
        }
        return std::any(m);
    }
    return std::any{};
}

// Load a program file into a BallDyn, mirroring the Dart CLI's `_loadProgram`
// error text + exit codes. Returns false (and sets `err`-routed messages) on
// failure; `code` carries the intended process exit code.
bool load_program(const std::string& path, BallDyn& out, int& code) {
    std::ifstream f(path, std::ios::binary);
    if (!f) {
        std::cerr << "Error: File not found: " << path << "\n";
        code = 1;
        return false;
    }
    std::stringstream ss;
    ss << f.rdbuf();
    nlohmann::json parsed;
    try {
        parsed = nlohmann::json::parse(ss.str());
    } catch (const std::exception& e) {
        std::cerr << "Error parsing JSON: " << e.what() << "\n";
        code = 1;
        return false;
    }
    out = BallDyn(json_to_ball(parsed));
    return true;
}

int usage(const char* verb) {
    std::cerr << "Usage: ball " << verb << " <input.ball.json>\n";
    return 1;
}

}  // namespace

namespace ballcli {

int cmd_info(const std::vector<std::string>& args) {
    if (args.empty()) return usage("info");
    BallDyn prog;
    int code = 0;
    if (!load_program(args[0], prog, code)) return code;
    std::cout << ball_to_string(cli_core::infoReport(prog)) << "\n";
    return 0;
}

int cmd_validate(const std::vector<std::string>& args) {
    if (args.empty()) return usage("validate");
    BallDyn prog;
    int code = 0;
    if (!load_program(args[0], prog, code)) return code;
    const std::string report = ball_to_string(cli_core::validateReport(prog));
    const bool ok = ball_to_string(cli_core::validateOk(prog)) == "true";
    if (ok) {
        std::cout << report << "\n";
        return 0;
    }
    std::cerr << report << "\n";
    return 1;
}

int cmd_tree(const std::vector<std::string>& args) {
    // Skip flags, take the first positional (matches the Dart CLI).
    std::string input;
    for (const auto& a : args) {
        if (a.rfind("-", 0) != 0) {
            input = a;
            break;
        }
    }
    if (input.empty()) return usage("tree");
    BallDyn prog;
    int code = 0;
    if (!load_program(input, prog, code)) return code;
    std::cout << ball_to_string(cli_core::treeReport(prog)) << "\n";
    return 0;
}

int cmd_audit(const std::vector<std::string>& args) {
    // Skip flags, take the first positional (matches the Dart CLI's `ball audit`
    // fast path, which ignores the native-only --deny/--exit-code/etc. flags
    // that are out of scope for the self-hosted verb).
    std::string input;
    for (const auto& a : args) {
        if (a.rfind("-", 0) != 0) {
            input = a;
            break;
        }
    }
    if (input.empty()) return usage("audit");
    BallDyn prog;
    int code = 0;
    if (!load_program(input, prog, code)) return code;
    // `auditReport` is already newline-terminated (its Dart source returns
    // "…\n"), and the Dart CLI emits it with `out.write` (no extra newline), so
    // print it as-is — no trailing "\n" like the other verbs.
    std::cout << ball_to_string(cli_core::auditReport(prog));
    return 0;
}

int cmd_version(const std::vector<std::string>&) {
    std::cout << ball_to_string(cli_core::versionLine(std::string(BALL_CLI_VERSION)))
              << "\n";
    return 0;
}

}  // namespace ballcli
